select count(*) from postgres.comments as c, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where v.userid = u.id and c.userid = u.id and ph.userid = u.id and c.creationdate<=timestamp '2014-08-28 07:25:55' and ph.posthistorytypeid=2 and u.reputation>=1 and u.views>=0 and u.downvotes>=0 and u.upvotes>=0 and u.upvotes<=15 and u.creationdate>=timestamp '2010-09-03 11:45:16' and u.creationdate<=timestamp '2014-08-18 17:19:53';
